#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = 0;

// fern fractal on the red channel

vec2 uv0 = vUv.yx*4 -vec2(3,0);
float c0 = texture(sampler_fc_main, uv0).z; // feeded by the spiral

vec2 uv1 = 0.5 + (vUv-0.5)*1.15 + vec2(-1,1)*0.05; // main arm
float1 c1 = texture(sampler_fc_main, uv1).x;

vec2 uv2 = vec2(-1,0) + (vec2(-1,1)*vUv + vec2(1,0) - 0.5)*4; // upper limb
float1 c2 = texture(sampler_fc_main, uv2).x;

vec2 uv3 = vec2(1,2) + (vec2(1,-1)*vUv + vec2(0,1) - 0.5)*4; // lower limb
float1 c3 = texture(sampler_fc_main, uv3).x;

ret.x = (c0 + c1 + c2 + c3)*1.075; // composition of the red fractal

// spiral in the blue channel

vec2 uv4 = vec2(-1,0) + (vec2(-1,1)*vUv + vec2(1,0) - 0.5)*4;
float1 c4 = texture(sampler_fc_main, uv4).x; // feeded by the fern

s = q1; // sin(w)
c = q2; // cos(w)
vec2 scale = 1.05;
vec2 uv5 = (vUv-0.5)*uAspect.xy;
       uv5 = scale*vec2( c*uv5.x - s*uv5.y, s*uv5.x + c*uv5.y); // rotation
       uv5 = 0.5 + uv5*uAspect.zw + vec2(-0.03,0.03);

float1 c5 = texture(sampler_fc_main, uv5).z;

ret.z = (c4 + c5)*1.075 - 0.00;

// mirrored rotated checker in the green channel

s = q3; // sin(w)
c = q4; // cos(w)

vec2 uv6 = (vUv-0.5)*uAspect.xy*2.4;
       uv6 = scale*vec2( c*uv6.x - s*uv6.y, s*uv6.x + c*uv6.y); // rotation
       uv6 = 0.5 + uv6*uAspect.zw + vec2(q9,q10);

       uv6 = 1.0 - abs( fract( uv6 * 0.5 ) * 2.0 - 1.0 ); // Eo.S' mirror code

float c6 = texture(sampler_fc_main,uv6).z; // feeded by the spiral
float c7 = texture(sampler_fc_main,uv6).y;

ret.y = mix(max(c6,c7-0.15),texture(sampler_fc_main,vUvOriginal).y-0.004,0.6); // motion blur


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv2;

    vec4 c = vec4(1,0.4,0.15,0.1);

    uv2 = vUv + vec2(1,0)*uTexSize.zw;
    float gx1 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;
    uv2 = vUv + vec2(-1,0)*uTexSize.zw;
    float gx2 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;

    uv2 = vUv + vec2(0,1)*uTexSize.zw;
    float gy1 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;
    uv2 = vUv + vec2(0,-1)*uTexSize.zw;
    float gy2 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;

    vec3 g = normalize(vec3(gx1-gx2, gy1-gy2, 0.14));

    ret = 0.5 + 0.5*g;
    ret *= clamp01(length(ret.xy-0.5)*5);
    ret = ret.xxy;
    ret += 1.15;
    ret *= mix(ret,ret*(GetBlur3(vUv)-GetBlur1(vUv)*audioHighSmooth),pow(hue_shader.xzy,audioLowSmooth));
    ret *= ret;

    //ret *= 1.5; //old gamma effect

  fragColor = ret;
}
